import{_ as e,o as t,c as o,aw as n}from"./chunks/framework.CrejmIte.js";const r=JSON.parse('{"title":"ADR 023: Execution-Owned Proposer Rotation","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 023: Execution-Owned Proposer Rotation | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-023-execution-owned-proposer-rotation.md","filePath":"adr/adr-023-execution-owned-proposer-rotation.md","lastUpdated":1777041091000}');const a=e({name:"adr/adr-023-execution-owned-proposer-rotation.md"},[["render",function(e,r,a,i,s,c){return t(),o("div",null,[...r[0]||(r[0]=[n('<h1 id="adr-023-execution-owned-proposer-rotation" tabindex="-1">ADR 023: Execution-Owned Proposer Rotation <a class="header-anchor" href="#adr-023-execution-owned-proposer-rotation" aria-label="Permalink to &quot;ADR 023: Execution-Owned Proposer Rotation&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>2026-04-24: Initial ADR.</li></ul><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ev-node originally selected the block proposer from genesis. That made proposer changes a consensus configuration concern and pushed key rotation into a static schedule. This is too rigid for EVM rollups and other execution environments where proposer selection should be governed by execution state.</p><p>The replacement design moves proposer selection into the execution environment. ev-node remains responsible for signing, propagating, validating, and persisting blocks, but it consumes proposer updates returned by execution.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><code>Executor.ExecuteTxs</code> returns an execution result containing:</p><ul><li><code>UpdatedStateRoot</code>: the state root after executing the block.</li><li><code>NextProposerAddress</code>: the address expected to sign the next block.</li></ul><p><code>GetExecutionInfo</code> also exposes <code>NextProposerAddress</code> for startup. If execution returns an empty proposer at startup, ev-node falls back to <code>genesis.proposer_address</code>.</p><p>An empty <code>NextProposerAddress</code> from <code>ExecuteTxs</code> means the proposer is unchanged. ev-node must not write a redundant header field in that case, preserving compatibility with existing headers and hash chains.</p><p>When execution returns a non-empty next proposer:</p><ul><li>The producing node commits it to <code>Header.NextProposerAddress</code> before signing the header.</li><li>Syncing nodes require the signed header value to match the execution result.</li><li><code>State.NextProposerAddress</code> is updated and used as the expected signer for <code>LastBlockHeight + 1</code>.</li></ul><p><code>Header.NextProposerAddress</code> lets header-only paths and DA envelope validation see proposer transitions without replaying execution first. The execution result remains the authority; mismatches between the signed header and execution are invalid.</p><h2 id="evm-system-contract-model" tabindex="-1">EVM System Contract Model <a class="header-anchor" href="#evm-system-contract-model" aria-label="Permalink to &quot;EVM System Contract Model&quot;">​</a></h2><p>For ev-reth, proposer selection should be implemented as execution state, likely through a system contract. The contract stores the active next proposer address and exposes controlled update methods.</p><p>The controlling address can be a multisig or security council. This keeps operational key rotation in execution state instead of requiring a new genesis file or node-side schedule. A future ev-reth implementation should read the contract during block execution and return the selected proposer through <code>ExecuteTxsResponse.next_proposer_address</code>.</p><p>This ADR does not define the system contract ABI. The contract should be specified with ev-reth because access control, call routing, and predeploy/system-contract conventions are execution-environment details.</p><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><p>The security council or multisig becomes the authority for proposer updates. It must use a threshold and operational process appropriate for production signer rotation.</p><p>The system contract must restrict writes to the configured authority. Unauthorized proposer updates are consensus-critical because they determine who can sign the next block.</p><p>ev-node validates the execution output against the signed header. A malicious proposer cannot advertise one next proposer in the header while execution derives another.</p><p>If the execution interface returns an empty proposer, ev-node treats the proposer as unchanged. At startup, empty execution info falls back to genesis so existing execution implementations remain usable.</p><p>Compromise of the security council can still rotate the proposer to an attacker. This ADR reduces node configuration risk; it does not eliminate governance-key risk.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li>Proposer rotation becomes deterministic execution state.</li><li>EVM chains can use a system contract and multisig-controlled rotation.</li><li>Existing chains keep working when execution returns an empty proposer.</li><li>Header verification can follow rotations once the rotating block is known.</li></ul><p>Negative:</p><ul><li>The execution API changes and all execution adapters must return <code>ExecuteResult</code>.</li><li>Proposer updates become consensus-critical execution outputs.</li><li>ev-reth needs a separate system-contract design and implementation.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><p>Genesis proposer schedule:</p><ul><li>Rejected. It makes rotation a static node/genesis concern and is not a good fit for security-council or multisig-controlled EVM deployments.</li></ul><p>Node-local proposer configuration:</p><ul><li>Rejected. Nodes could disagree about the active proposer unless every operator updates configuration at the same time.</li></ul><p>Execution-only proposer without header commitment:</p><ul><li>Rejected. Syncing nodes can replay execution, but header and DA envelope paths benefit from having the selected next proposer committed in the signed header when it changes.</li></ul>',38)])])}]]);export{r as __pageData,a as default};
